INSERT INTO `1708882270_eaqv_cmplz_cookiebanners` (`ID`, `banner_version`, `default`, `archived`, `title`, `position`, `theme`, `checkbox_style`, `use_logo`, `logo_attachment_id`, `close_button`, `revoke`, `manage_consent_options`, `header`, `dismiss`, `save_preferences`, `view_preferences`, `category_functional`, `category_all`, `category_stats`, `category_prefs`, `accept`, `message_optin`, `use_categories`, `disable_cookiebanner`, `banner_width`, `soft_cookiewall`, `dismiss_on_scroll`, `dismiss_on_timeout`, `dismiss_timeout`, `accept_informational`, `message_optout`, `use_custom_cookie_css`, `custom_css`, `statistics`, `functional_text`, `statistics_text`, `statistics_text_anonymous`, `preferences_text`, `marketing_text`, `colorpalette_background`, `colorpalette_text`, `colorpalette_toggles`, `colorpalette_border_radius`, `border_width`, `font_size`, `colorpalette_button_accept`, `colorpalette_button_deny`, `colorpalette_button_settings`, `buttons_border_radius`, `animation`, `use_box_shadow`, `header_footer_shadow`, `hide_preview`, `disable_width_correction`, `legal_documents`) VALUES (1,12,1,0,'bottom-right view-preferences','bottom-right','','slider','hide',0,1,'Spravovat souhlas','hover-hide-mobile','a:2:{s:4:\"text\";s:27:\"Spravovat Souhlas s cookies\";s:4:\"show\";i:1;}','a:2:{s:4:\"text\";s:10:\"Odmítnout\";s:4:\"show\";i:1;}','Uložit předvolby','Zobrazit předvolby','Funkční','a:2:{s:4:\"text\";s:9:\"Marketing\";s:4:\"show\";i:1;}','a:2:{s:4:\"text\";s:10:\"Statistiky\";s:4:\"show\";i:1;}','a:2:{s:4:\"text\";s:0:\"\";s:4:\"show\";b:1;}','Příjmout','Abychom poskytli co nejlepší služby, používáme k ukládání a/nebo přístupu k informacím o zařízení, technologie jako jsou soubory cookies. Souhlas s těmito technologiemi nám umožní zpracovávat údaje, jako je chování při procházení nebo jedinečná ID na tomto webu. Nesouhlas nebo odvolání souhlasu může nepříznivě ovlivnit určité vlastnosti a funkce.','view-preferences',0,526,0,0,0,10,'a:2:{s:4:\"text\";s:0:\"\";s:4:\"show\";b:1;}','Abychom poskytli co nejlepší služby, používáme k ukládání a/nebo přístupu k informacím o zařízení, technologie jako jsou soubory cookies. Souhlas s těmito technologiemi nám umožní zpracovávat údaje, jako je chování při procházení nebo jedinečná ID na tomto webu. Nesouhlas nebo odvolání souhlasu může nepříznivě ovlivnit určité vlastnosti a funkce.',0,'/* Container */\r\n.cmplz-cookiebanner{}\r\n\r\n/* Logo */\r\n.cmplz-cookiebanner .cmplz-logo{}\r\n/* Title */\r\n.cmplz-cookiebanner .cmplz-title{}\r\n/* Close icon */\r\n.cmplz-cookiebanner .cmplz-close{}\r\n\r\n/* Message */\r\n.cmplz-cookiebanner .cmplz-message{}\r\n\r\n /* All buttons */\r\n.cmplz-buttons .cmplz-btn{}\r\n/* Accept button */\r\n.cmplz-btn .cmplz-accept{} \r\n /* Deny button */\r\n.cmplz-btn .cmplz-deny{}\r\n /* Save preferences button */\r\n.cmplz-btn .cmplz-deny{}\r\n /* View preferences button */\r\n.cmplz-btn .cmplz-deny{}\r\n\r\n /* Document hyperlinks */\r\n.cmplz-links .cmplz-documents{}\r\n\r\n /* Categories */\r\n.cmplz-cookiebanner .cmplz-category{}\r\n.cmplz-cookiebanner .cmplz-category-title{} \r\n\r\n/* Manage consent tab */\r\n#cmplz-manage-consent .cmplz-manage-consent{} \r\n\r\n/* Soft cookie wall */\r\n.cmplz-soft-cookiewall{}\r\n\r\n/* Placeholder button - Per category */\r\n.cmplz-blocked-content-container .cmplz-blocked-content-notice{}\r\n\r\n/* Placeholder button & message - Per service */\r\n.cmplz-blocked-content-container .cmplz-blocked-content-notice,\r\n.cmplz-blocked-content-notice{}\r\nbutton.cmplz-accept-service{}\r\n\r\n/* Styles for the AMP notice */\r\n#cmplz-consent-ui, #cmplz-post-consent-ui {}\r\n/* Message */\r\n#cmplz-consent-ui .cmplz-consent-message {}\r\n/* Buttons */\r\n#cmplz-consent-ui button, #cmplz-post-consent-ui button {}','a:0:{}','a:2:{s:4:\"text\";s:285:\"Technické uložení nebo přístup je nezbytně nutný pro legitimní účel umožnění použití konkrétní služby, kterou si odběratel nebo uživatel výslovně vyžádal, nebo pouze za účelem provedení přenosu sdělení prostřednictvím sítě elektronických komunikací.\";s:4:\"show\";i:1;}','a:2:{s:4:\"text\";s:0:\"\";s:4:\"show\";b:1;}','a:2:{s:4:\"text\";s:350:\"Technické uložení nebo přístup, který se používá výhradně pro anonymní statistické účely. Bez předvolání, dobrovolného plnění ze strany vašeho Poskytovatele internetových služeb nebo dalších záznamů od třetí strany nelze informace, uložené nebo získané pouze pro tento účel, obvykle použít k vaší identifikaci.\";s:4:\"show\";i:1;}','a:2:{s:4:\"text\";s:0:\"\";s:4:\"show\";b:1;}','a:2:{s:4:\"text\";s:242:\"Technické uložení nebo přístup je nutný k vytvoření uživatelských profilů za účelem zasílání reklamy nebo sledování uživatele na webových stránkách nebo několika webových stránkách pro podobné marketingové účely.\";s:4:\"show\";i:1;}','a:2:{s:5:\"color\";s:7:\"#ffffff\";s:6:\"border\";s:7:\"#f2f2f2\";}','a:2:{s:5:\"color\";s:7:\"#222222\";s:9:\"hyperlink\";s:7:\"#1E73BE\";}','a:3:{s:10:\"background\";s:7:\"#1e73be\";s:6:\"bullet\";s:7:\"#ffffff\";s:8:\"inactive\";s:7:\"#F56E28\";}','a:5:{s:3:\"top\";i:12;s:5:\"right\";i:12;s:6:\"bottom\";i:12;s:4:\"left\";i:12;s:4:\"type\";s:2:\"px\";}','a:4:{s:3:\"top\";i:0;s:5:\"right\";i:0;s:6:\"bottom\";i:0;s:4:\"left\";i:0;}',12,'a:3:{s:10:\"background\";s:7:\"#1E73BE\";s:6:\"border\";s:7:\"#1E73BE\";s:4:\"text\";s:7:\"#ffffff\";}','a:3:{s:10:\"background\";s:7:\"#f9f9f9\";s:6:\"border\";s:7:\"#f2f2f2\";s:4:\"text\";s:7:\"#222222\";}','a:3:{s:10:\"background\";s:7:\"#f9f9f9\";s:6:\"border\";s:7:\"#f2f2f2\";s:4:\"text\";s:7:\"#333333\";}','a:5:{s:3:\"top\";i:6;s:5:\"right\";i:6;s:6:\"bottom\";i:6;s:4:\"left\";i:6;s:4:\"type\";s:2:\"px\";}','none',1,0,0,0,1);
